{% extends "base.html" %}

{% block title %}Todo List{% endblock %}

{% block nav %}
<a href="/register" class="visually-hidden">Create account</a>
<a href="/login" class="visually-hidden">Sign in</a>
{% endblock %}

{% block content %}
<div class="landing-hero">
    <h1>Welcome</h1>
    <p>Keep track of what you need to do.</p>
    <div class="landing-hero__actions">
        <a href="/register" class="landing-hero__cta">Create account</a>
        <p class="landing-hero__alt">Already have an account? <a href="/login">Sign in</a></p>
    </div>
</div>
{% endblock %}

{% extends "base.html" %}

{% block title %}My Todos -- Todo List{% endblock %}

{% block nav %}
<form method="post" action="/logout" class="nav-logout" hx-boost="false">
    <button type="submit" class="nav-logout__button">Sign out</button>
</form>
{% endblock %}

{% block scripts %}
<script src="/static/js/todo-focus.js"></script>
{% endblock %}

{% block content %}
<div class="todo-page">
    <h1>My Todos</h1>

    <form method="post" action="/todos" class="todo-add"
        hx-post="/todos" hx-target=".todo-list" hx-swap="beforeend" hx-on::after-request="if(event.detail.successful) this.reset()">
        <div class="todo-add__group">
            <label for="title">New todo</label>
            <input
                type="text"
                id="title"
                name="title"
                placeholder="What do you need to do?"
                maxlength="300"
                autocomplete="off"
                aria-describedby="add-todo-error"
                {% if error_message.is_some() %}aria-invalid="true"{% endif %}
            >
        </div>
        <button type="submit" class="todo-add__submit">Add todo</button>
    </form>

    <p class="todo-add__error" id="add-todo-error" role="alert">{% if let Some(error) = error_message %}{{ error }}{% endif %}</p>

    <p class="todo-empty" id="todo-empty"{% if !todos.is_empty() %} hidden{% endif %}>No todos yet.</p>
    <ul class="todo-list" role="list"{% if todos.is_empty() %} hidden{% endif %}>
        {% for todo in todos %}
        {% include "todo_item.html" %}
        {% endfor %}
    </ul>
</div>
{% endblock %}

